import streamlit as st
import anthropic
import os

# Set your Anthropic API key as an environment variable or directly in the code (not recommended for security)
ANTHROPIC_API_KEY = os.environ.get("ANTHROPIC_API_KEY")  # Get API key from environment variable
if not ANTHROPIC_API_KEY:
    st.error("Please set the ANTHROPIC_API_KEY environment variable.")
    st.stop()

client = anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)

def summarize_paper(paper_text):
    """
    Summarizes a research paper using the Anthropic Claude API.

    Args:
        paper_text (str): The text of the research paper.

    Returns:
        str: The summary of the paper, or an error message if summarization fails.
    """
    try:
        response = client.messages.create(
            model="claude-3-opus-20240229",  # Or another suitable Claude model
            max_tokens=1024,
            messages=[
                {
                    "role": "user",
                    "content": f"Please provide a concise summary of the following research paper:\n\n{paper_text}",
                }
            ],
        )
        return response.content[0].text
    except Exception as e:
        return f"Error during summarization: {e}"


def ask_question(paper_text, question):
    """
    Asks a question about a research paper using the Anthropic Claude API.

    Args:
        paper_text (str): The text of the research paper.
        question (str): The question to ask about the paper.

    Returns:
        str: The answer to the question, or an error message if the question answering fails.
    """
    try:
        response = client.messages.create(
            model="claude-3-opus-20240229",  # Or another suitable Claude model
            max_tokens=512,
            messages=[
                {
                    "role": "user",
                    "content": f"Here is a research paper:\n\n{paper_text}\n\nAnswer the following question about the paper: {question}",
                }
            ],
        )
        return response.content[0].text
    except Exception as e:
        return f"Error during question answering: {e}"


def main():
    st.title("Research Paper Summarizer")

    paper_text = st.text_area("Enter the text of the research paper:", height=300)

    if st.button("Summarize Paper"):
        if paper_text:
            with st.spinner("Summarizing..."):
                summary = summarize_paper(paper_text)
            st.subheader("Summary:")
            st.write(summary)
            st.session_state.last_paper = paper_text  # Store the paper for question answering
            st.session_state.last_summary = summary
        else:
            st.warning("Please enter the text of the research paper.")

    if "last_paper" in st.session_state:
        question = st.text_input("Ask a question about the summarized paper:")
        if question:
            with st.spinner("Answering..."):
                answer = ask_question(st.session_state.last_paper, question)
            st.subheader("Answer:")
            st.write(answer)

if __name__ == "__main__":
    if "last_paper" not in st.session_state:
        st.session_state.last_paper = None
    if "last_summary" not in st.session_state:
        st.session_state.last_summary = None
    main()

