import streamlit as st
import anthropic

def summarize_document(document_text):
    """
    Summarizes a document using the Anthropic Claude API.

    Args:
        document_text: The text of the document to summarize.

    Returns:
        A string containing the summary of the document, or None if an error occurred.
    """
    try:
        client = anthropic.Anthropic()
        response = client.messages.create(
            model="claude-3-opus-20240229",  # Replace with your desired Claude model
            max_tokens=1024,
            messages=[
                {
                    "role": "user",
                    "content": f"Please summarize the following document:\n\n{document_text}"
                }
            ]
        )
        return response.content[0].text
    except Exception as e:
        st.error(f"Error summarizing document: {e}")
        return None

def ask_about_summary(summary_text, question):
    """
    Asks a question about the summary using the Anthropic Claude API.

    Args:
        summary_text: The text of the summary.
        question: The question to ask about the summary.

    Returns:
        A string containing the answer to the question, or None if an error occurred.
    """
    try:
        client = anthropic.Anthropic()
        response = client.messages.create(
            model="claude-3-opus-20240229",  # Replace with your desired Claude model
            max_tokens=1024,
            messages=[
                {
                    "role": "user",
                    "content": f"Here is a summary: {summary_text}\n\nQuestion: {question}"
                }
            ]
        )
        return response.content[0].text
    except Exception as e:
        st.error(f"Error asking about summary: {e}")
        return None

def main():
    st.title("Document Summarizer")

    uploaded_file = st.file_uploader("Upload a document (e.g., .txt, .pdf)", type=["txt", "pdf"])

    if uploaded_file is not None:
        try:
            if uploaded_file.type == "text/plain":
                document_text = uploaded_file.read().decode("utf-8")
            elif uploaded_file.type == "application/pdf":
                import pypdf
                pdf_reader = pypdf.PdfReader(uploaded_file)
                document_text = ""
                for page in pdf_reader.pages:
                    document_text += page.extract_text()
            else:
                st.error("Unsupported file type. Please upload a .txt or .pdf file.")
                return
        except Exception as e:
            st.error(f"Error reading file: {e}")
            return

        if st.button("Summarize Document"):
            with st.spinner("Summarizing..."):
                summary = summarize_document(document_text)

            if summary:
                st.subheader("Summary:")
                st.write(summary)

                question = st.text_input("Ask a question about the summary:")
                if question:
                    with st.spinner("Answering question..."):
                        answer = ask_about_summary(summary, question)
                    if answer:
                        st.subheader("Answer:")
                        st.write(answer)
    else:
        st.info("Please upload a document to summarize.")

if __name__ == "__main__":
    main()

