        response = client.messages.create(
            model="claude-3-opus-20240229",  # Or another suitable Claude model
            max_tokens=500,  # Adjust as needed
            messages=[
                {
                    "role": "user",
                    "content": f"Please summarize the following newspaper article:\n\n{article_text}",
