import anthropic
import newspaper
import streamlit as st

def summarize_article(article_text, api_key):
    """Summarizes an article using the Claude API."""
    client = anthropic.Anthropic(api_key=api_key)
    prompt = f"""Here is an article:

    {article_text}

    Please provide a concise summary of the article in 3-5 sentences.
    """

    try:
        response = client.completions.create(
            model="claude-v1.3",  # Or another suitable Claude model
            prompt=f"{anthropic.HUMAN_PROMPT} {prompt}{anthropic.AI_PROMPT}",
            max_tokens_to_sample=500,
        )
        return response.completion
    except Exception as e:
        return f"Error summarizing article: {e}"

def get_article_text(url):
    """Fetches the text content of an article from a URL."""
    try:
        article = newspaper.Article(url)
        article.download()
        article.parse()
        return article.text
    except Exception as e:
        return f"Error fetching article: {e}"

def ask_question(summary, question, api_key):
    """Asks a question about the summarized article using the Claude API."""
    client = anthropic.Anthropic(api_key=api_key)
    prompt = f"""Here is a summary of a newspaper article:

    {summary}

    Based on this summary, please answer the following question:

    {question}
    """

    try:
        response = client.completions.create(
            model="claude-v1.3",  # Or another suitable Claude model
            prompt=f"{anthropic.HUMAN_PROMPT} {prompt}{anthropic.AI_PROMPT}",
            max_tokens_to_sample=200,
        )
        return response.completion
    except Exception as e:
        return f"Error answering question: {e}"


def main():
    """Main function to run the Streamlit app."""
    st.title("Newspaper Summarizer")

    api_key = st.text_input("Enter your Anthropic API Key:", type="password")

    article_url = st.text_input("Enter the URL of the newspaper article:")

    if st.button("Summarize"):
        if not api_key:
            st.error("Please enter your Anthropic API key.")
        elif not article_url:
            st.error("Please enter a newspaper article URL.")
        else:
            with st.spinner("Fetching and summarizing article..."):
                article_text = get_article_text(article_url)
                if "Error" in article_text:
                    st.error(article_text)
                else:
                    summary = summarize_article(article_text, api_key)
