import streamlit as st
import anthropic

def summarize_paper(paper_text):
    """
    Summarizes a paper using the Anthropic Claude API.

    Args:
        paper_text: The text of the paper to summarize.

    Returns:
        A string containing the summary of the paper, or None if an error occurred.
    """
    try:
        client = anthropic.Anthropic()
        response = client.messages.create(
            model="claude-3-opus-20240229",  # Or another suitable Claude model
            max_tokens=1024,
            messages=[
                {
                    "role": "user",
                    "content": f"Please provide a concise summary of the following research paper:\n\n{paper_text}"
                }
            ]
        )
        return response.content[0].text
    except Exception as e:
        st.error(f"Error summarizing paper: {e}")
        return None

def ask_question(summary, question):
    """
    Asks a question about the summarized paper using the Anthropic Claude API.

    Args:
        summary: The summary of the paper.
        question: The question to ask.

    Returns:
        A string containing the answer to the question, or None if an error occurred.
    """
    try:
        client = anthropic.Anthropic()
        response = client.messages.create(
            model="claude-3-opus-20240229",  # Or another suitable Claude model
            max_tokens=512,
            messages=[
                {
                    "role": "user",
                    "content": f"I have the following summary of a research paper:\n\n{summary}\n\nAnswer the following question based on the summary: {question}"
                }
            ]
        )
        return response.content[0].text
    except Exception as e:
        st.error(f"Error asking question: {e}")
        return None

def main():
    st.title("Paper Summarizer and Question Answering")

    paper_text = st.text_area("Enter the text of the paper:", height=300)

